// TRF_ValidateAndPrepare V3 - handles both object and string agent output
const envelope = $('TRF_PrepareContext').item.json.envelope;
const agentOutput = $('Agent_Config').item.json;

let config_type = 'lead_time';
let lead_time_minutes = null;
let timezone = null;
let master_password = null;
let confirmation_text = '';
let is_valid = true;
let validation_error = '';
let item_action = null;
let item_search = null;
let modify_fields = null;
let add_attendees = null;
let remove_attendees = null;

try {
  let parsed = agentOutput;

  // If output is nested under .output key
  if (agentOutput.output) {
    const out = agentOutput.output;
    // If it's already an object, use directly
    if (typeof out === 'object' && out !== null) {
      parsed = out;
    } else if (typeof out === 'string') {
      // If it's a string, try to parse as JSON
      const cleaned = out.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
      parsed = JSON.parse(cleaned);
    }
  }

  config_type = parsed.config_type || 'lead_time';
  lead_time_minutes = parsed.lead_time_minutes;
  timezone = parsed.timezone;
  master_password = parsed.master_password;
  confirmation_text = parsed.confirmation_text || '';
  item_action = parsed.item_action || null;
  item_search = parsed.item_search || null;
  modify_fields = parsed.modify_fields || null;
  add_attendees = parsed.add_attendees || null;
  remove_attendees = parsed.remove_attendees || null;
} catch (e) {
  is_valid = false;
  validation_error = 'Failed to parse agent output: ' + e.message;
}

// Build upsert data based on config_type
const upsert_data = {
  owner_phone: envelope.from_phone,
  updated_at: new Date().toISOString()
};

if (config_type === 'lead_time') {
  if (!lead_time_minutes || lead_time_minutes < 1 || lead_time_minutes > 1440) {
    lead_time_minutes = 15;
  }
  upsert_data.lead_time_default_seconds = lead_time_minutes * 60;
  if (timezone) upsert_data.timezone = timezone;
  if (!confirmation_text) {
    confirmation_text = 'Pronto! Vou te avisar ' + lead_time_minutes + ' minutos antes dos compromissos.';
  }
} else if (config_type === 'master_password') {
  if (!master_password || master_password.length < 2 || master_password.length > 50) {
    is_valid = false;
    validation_error = 'Contrasenha inválida. Deve ter entre 2 e 50 caracteres.';
    confirmation_text = 'A contrasenha precisa ter entre 2 e 50 caracteres. Tente novamente.';
  } else {
    upsert_data.master_password = master_password;
    if (!confirmation_text) {
      confirmation_text = '🔐 Contrasenha cadastrada com sucesso! Suas notas sensíveis agora estão protegidas.';
    }
  }
} else if (config_type === 'timezone') {
  if (timezone) {
    upsert_data.timezone = timezone;
    if (!confirmation_text) {
      confirmation_text = '🌎 Fuso horário atualizado para ' + timezone + '.';
    }
  } else {
    is_valid = false;
    validation_error = 'Timezone não informado';
    confirmation_text = 'Não entendi o fuso horário. Pode repetir?';
  }
} else if (config_type === 'manage_item') {
  if (!item_action || !item_search) {
    is_valid = false;
    validation_error = 'Ação ou busca não identificada';
    confirmation_text = 'Não consegui identificar o que você quer alterar. Pode ser mais específico?';
  } else {
    if (!confirmation_text) {
      confirmation_text = 'Processando ' + item_action + ' de "' + item_search + '"...';
    }
  }
}

return [{
  json: {
    envelope: envelope,
    config: {
      config_type: config_type,
      item_action: item_action,
      item_search: item_search,
      modify_fields: modify_fields,
      add_attendees: add_attendees,
      remove_attendees: remove_attendees,
      lead_time_minutes: lead_time_minutes,
      timezone: timezone,
      master_password: master_password ? '***' : null,
      confirmation_text: confirmation_text
    },
    validation: {
      is_valid: is_valid,
      error: validation_error
    },
    upsert_data: upsert_data
  }
}];

// DB_UpsertPrefs V6 - Save preferences including master_password (secure env vars)
const prepared = $('TRF_ValidateAndPrepare').item.json;
const upsertData = prepared.upsert_data;
const config = prepared.config;
const supabaseUrl = 'https://chtkfksjqcvlxpgyzlsf.supabase.co';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImNodGtma3NqcWN2bHhwZ3l6bHNmIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MjMwODU1NywiZXhwIjoyMDg3ODg0NTU3fQ.DM9wL7MlXRBuM_IYDk3pQ_q-WE7DYuwpqTTywg5A05U';

if (!supabaseUrl || !supabaseKey) {
  return [{ json: { success: false, error: 'Missing SUPABASE_URL or SUPABASE_KEY environment variables' } }];
}

const headers = {
  apikey: supabaseKey,
  Authorization: 'Bearer ' + supabaseKey,
  'Content-Type': 'application/json',
  Prefer: 'return=representation'
};

const ownerPhone = upsertData.owner_phone;
const body = { updated_at: new Date().toISOString() };
const configType = config.config_type;

if (configType === 'master_password' && upsertData.master_password) {
  body.lead_time_scope = 'master_pwd:' + upsertData.master_password;
} else if (configType === 'lead_time') {
  if (upsertData.lead_time_default_seconds) {
    body.lead_time_minutes = Math.round(upsertData.lead_time_default_seconds / 60);
  } else if (config.lead_time_minutes) {
    body.lead_time_minutes = config.lead_time_minutes;
  }
} else if (configType === 'timezone' && upsertData.timezone) {
  body.timezone = upsertData.timezone;
}

try {
  const existing = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/user_prefs?owner_phone=eq.' + encodeURIComponent(ownerPhone) + '&select=owner_phone',
    headers: { apikey: supabaseKey, Authorization: 'Bearer ' + supabaseKey },
    json: true
  });

  let result;
  if (existing && existing.length > 0) {
    result = await this.helpers.httpRequest({
      method: 'PATCH',
      url: supabaseUrl + '/rest/v1/user_prefs?owner_phone=eq.' + encodeURIComponent(ownerPhone),
      headers,
      body,
      json: true
    });
  } else {
    body.owner_phone = ownerPhone;
    result = await this.helpers.httpRequest({
      method: 'POST',
      url: supabaseUrl + '/rest/v1/user_prefs',
      headers,
      body,
      json: true
    });
  }

  return [{ json: { success: true, data: result } }];
} catch (e) {
  return [{ json: { success: false, error: e.message } }];
}

// TRF_FormatResponse (V5: robust manage_item + modify + error handling)
const prepared = $('TRF_ValidateAndPrepare').item.json;
const config = prepared.config;
const validation = prepared.validation;
let responseText = '';

// If validation failed, return the error message
if (!validation.is_valid) {
  responseText = config.confirmation_text || 'Não entendi o que você quer configurar. Pode repetir?';
  return [{
    json: {
      envelope: prepared.envelope,
      agent_response: {
        text: responseText,
        agent: 'CONFIG',
        config_updated: { config_type: config.config_type }
      }
    }
  }];
}

// Handle manage_item results
if (config.config_type === 'manage_item') {
  try {
    const manageResult = $('DB_ManageItem').item.json;

    if (manageResult._error) {
      responseText = manageResult._error;
    } else if (manageResult.title) {
      const action = manageResult.action || config.item_action || 'atualizado';
      const actionLabels = {
        cancel: 'cancelado',
        done: 'concluído',
        delete: 'excluído',
        modify: 'atualizado'
      };
      const actionEmojis = {
        cancel: '❌',
        done: '✅',
        delete: '🗑️',
        modify: '✏️'
      };
      const emoji = actionEmojis[action] || '✏️';
      const label = actionLabels[action] || 'atualizado';
      responseText = emoji + ' "' + manageResult.title + '" ' + label + ' com sucesso!';

      // Add modify details
      if (action === 'modify' && manageResult.modify_fields) {
        const mf = manageResult.modify_fields;
        const details = [];
        if (mf.new_title) details.push('Título: ' + mf.new_title);
        if (mf.new_event_datetime) {
          const dt = new Date(mf.new_event_datetime);
          details.push('Data/hora: ' + dt.toLocaleString('pt-BR', {timeZone: 'America/Belem'}));
        }
        if (mf.new_duration_minutes) details.push('Duração: ' + mf.new_duration_minutes + ' min');
        if (mf.add_attendees && mf.add_attendees.length > 0) details.push('Convidados adicionados: ' + mf.add_attendees.join(', '));
        if (mf.remove_attendees && mf.remove_attendees.length > 0) details.push('Convidados removidos: ' + mf.remove_attendees.join(', '));

        if (details.length > 0) {
          responseText += '\n' + details.join('\n');
        }
      }

      // Add Google sync result
      try {
        const syncResult = $('TRF_GoogleSync').item.json;
        if (syncResult._google_sync_result) {
          responseText += syncResult._google_sync_result;
        }
      } catch(e) {}
    }
  } catch(e) {
    responseText = config.confirmation_text || 'Erro ao processar a ação.';
  }
} else {
  // Preference updates (lead_time, timezone, master_password)
  responseText = config.confirmation_text || 'Configuração atualizada!';
}

return [{
  json: {
    envelope: prepared.envelope,
    agent_response: {
      text: responseText,
      agent: 'CONFIG',
      config_updated: {
        config_type: config.config_type,
        lead_time_minutes: config.lead_time_minutes,
        timezone: config.timezone,
        master_password_set: config.master_password ? true : false
      }
    }
  }
}];

// DB_ManageItem V6 - improved fuzzy search with stopwords + keyword weighting
const prepared = $('TRF_ValidateAndPrepare').item.json;
const config = prepared.config;
const envelope = prepared.envelope;
const action = config.item_action;
const searchText = config.item_search;
const modifyFields = config.modify_fields || {};

if (!action || !searchText) {
  return [{ json: { _error: 'Não entendi qual item você quer gerenciar. Pode repetir?' } }];
}

const supabaseUrl = 'https://chtkfksjqcvlxpgyzlsf.supabase.co';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImNodGtma3NqcWN2bHhwZ3l6bHNmIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MjMwODU1NywiZXhwIjoyMDg3ODg0NTU3fQ.DM9wL7MlXRBuM_IYDk3pQ_q-WE7DYuwpqTTywg5A05U';
const headers = {
  apikey: supabaseKey,
  Authorization: 'Bearer ' + supabaseKey,
  'Content-Type': 'application/json',
  Prefer: 'return=representation'
};
const ownerPhone = envelope.from_phone;

// Stopwords to ignore in search
const STOPWORDS = new Set([
  'a', 'o', 'e', 'de', 'do', 'da', 'dos', 'das', 'no', 'na', 'nos', 'nas',
  'em', 'um', 'uma', 'uns', 'umas', 'para', 'pra', 'pro', 'por', 'com',
  'sem', 'que', 'se', 'ao', 'aos', 'dia', 'até', 'ate', 'meu', 'minha',
  'esse', 'essa', 'este', 'esta', 'aquele', 'aquela', 'ele', 'ela',
  'me', 'te', 'lhe', 'nos', 'vos', 'lhes', 'eu', 'tu', 'nós', 'vós',
  'cancela', 'cancelar', 'cancele', 'exclui', 'excluir', 'exclua',
  'remove', 'remover', 'remova', 'deleta', 'deletar', 'delete',
  'marca', 'marcar', 'marque', 'como', 'feito', 'feita', 'concluido', 'concluida',
  'altera', 'alterar', 'altere', 'modifica', 'modificar', 'modifique',
  'muda', 'mudar', 'mude', 'troca', 'trocar', 'troque',
  'adiciona', 'adicionar', 'adicione', 'add',
  'reuniao', 'reunião', 'tarefa', 'nota', 'lembrete', 'evento'
]);

try {
  // Extract meaningful keywords (remove stopwords, short words)
  const keywords = searchText
    .toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '') // remove accents for matching
    .replace(/[^a-z0-9\s]/gi, '')
    .split(/\s+/)
    .filter(w => w.length > 1 && !STOPWORDS.has(w));

  // Also keep accented version for ilike
  const keywordsOriginal = searchText
    .toLowerCase()
    .replace(/[^a-záàâãéèêíïóôõöúçñ0-9\s]/gi, '')
    .split(/\s+/)
    .filter(w => w.length > 1);

  // Strategy 1: Direct ilike search with cleaned search text
  const cleanSearch = searchText
    .replace(/^(cancela|cancelar|exclui|excluir|marca|marcar|altera|alterar|modifica|modificar|remove|remover|adiciona|adicionar)\s+/i, '')
    .replace(/^(a |o |as |os |meu |minha |esse |essa |este |esta )/i, '')
    .replace(/^(reuni[aã]o|tarefa|nota|lembrete|evento)[:\s]*/i, '')
    .trim();

  let searchResp = [];
  if (cleanSearch.length > 2) {
    searchResp = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/rest/v1/items?owner_phone=eq.' +
        encodeURIComponent(ownerPhone) +
        '&status=neq.cancelled&title=ilike.*' +
        encodeURIComponent(cleanSearch) +
        '*&order=created_at.desc&limit=5',
      headers,
      json: true
    });
  }

  // Strategy 2: Keyword-weighted fuzzy search on all items
  if (!searchResp || searchResp.length === 0) {
    const allItems = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/rest/v1/items?owner_phone=eq.' +
        encodeURIComponent(ownerPhone) +
        '&status=neq.cancelled&order=created_at.desc&limit=50',
      headers,
      json: true
    });

    const scored = allItems.map(item => {
      const titleLower = (item.title || '').toLowerCase()
        .normalize('NFD').replace(/[\u0300-\u036f]/g, '');
      let score = 0;
      let matchedKeywords = 0;

      for (const kw of keywords) {
        if (titleLower.includes(kw)) {
          // Weight by keyword length: longer keywords are more specific
          score += kw.length;
          matchedKeywords++;
        }
      }

      // Bonus: percentage of keywords matched
      const matchRatio = keywords.length > 0 ? matchedKeywords / keywords.length : 0;
      score *= (1 + matchRatio);

      return { item, score, matchedKeywords, matchRatio };
    })
    .filter(s => s.score > 0)
    .sort((a, b) => {
      // Primary: score descending
      if (b.score !== a.score) return b.score - a.score;
      // Secondary: match ratio descending
      if (b.matchRatio !== a.matchRatio) return b.matchRatio - a.matchRatio;
      // Tertiary: most recent first
      return new Date(b.item.created_at || 0) - new Date(a.item.created_at || 0);
    });

    if (scored.length > 0) {
      searchResp = [scored[0].item];
    }
  }

  if (!searchResp || searchResp.length === 0) {
    return [{ json: { _error: 'Não encontrei nenhum item com "' + searchText + '". Verifique o nome e tente novamente.' } }];
  }

  const bestMatch = searchResp[0];
  const updateBody = { updated_at: new Date().toISOString() };
  let needsGCalDelete = false;
  let needsGCalUpdate = false;
  let needsGTasksDelete = false;
  let needsGTasksDone = false;

  if (action === 'cancel' || action === 'delete') {
    updateBody.status = 'cancelled';
    needsGCalDelete = !!bestMatch.google_calendar_event_id;
    needsGTasksDelete = !!bestMatch.google_tasks_task_id;
  } else if (action === 'done') {
    updateBody.status = 'done';
    updateBody.completed_at = new Date().toISOString();
    needsGTasksDone = !!bestMatch.google_tasks_task_id;
  } else if (action === 'modify') {
    needsGCalUpdate = !!bestMatch.google_calendar_event_id;
    if (modifyFields.new_title) updateBody.title = modifyFields.new_title;
    if (modifyFields.new_event_datetime) updateBody.event_datetime = modifyFields.new_event_datetime;
    if (modifyFields.new_attendees) updateBody.attendees = modifyFields.new_attendees;
  }

  await this.helpers.httpRequest({
    method: 'PATCH',
    url: supabaseUrl + '/rest/v1/items?id=eq.' + bestMatch.id,
    headers,
    body: updateBody,
    json: true
  });

  return [{
    json: {
      title: modifyFields.new_title || bestMatch.title,
      type: bestMatch.type,
      action,
      new_status: updateBody.status || bestMatch.status,
      item_id: bestMatch.id,
      google_calendar_event_id: bestMatch.google_calendar_event_id || null,
      google_tasks_task_id: bestMatch.google_tasks_task_id || null,
      modify_fields: config.modify_fields || null,
      _needs_google_calendar_delete: needsGCalDelete,
      _needs_google_tasks_delete: needsGTasksDelete,
      _needs_google_calendar_update: needsGCalUpdate,
      _needs_google_tasks_done: needsGTasksDone
    }
  }];
} catch (e) {
  return [{ json: { _error: 'Erro ao buscar item: ' + e.message } }];
}

// Prepare chatInput for Agent_Config
const input = $('TRG_FromOrchestrator').item.json;
let envelope = input.envelope;
// GUARDRAIL: envelope pode vir como string
if (typeof envelope === 'string') {
  try { envelope = JSON.parse(envelope); } catch(e) { envelope = { user_message: envelope, text_raw: envelope }; }
}
const userMessage = envelope.user_message || envelope.text_raw || 'mensagem vazia';
const ownerPhone = envelope.from_phone || '';
const tz = (envelope.prefs && envelope.prefs.timezone) || 'America/Belem';

// Build date/time context
const now = new Date();
const localOptions = { timeZone: tz, year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false };
let localTime;
try {
  localTime = now.toLocaleString('pt-BR', localOptions);
} catch(e) {
  localTime = now.toISOString();
}

// Build chatInput with context
const chatInput = `Analise a mensagem do usuário e extraia a configuração.
MENSAGEM: ${userMessage}
DATA/HORA LOCAL: ${localTime}
FUSO HORÁRIO: ${tz} (GMT-3)
Converta horários locais para UTC somando 3 horas.`;

return [{
  json: {
    chatInput: chatInput,
    envelope: envelope,
    owner_phone: ownerPhone
  }
}];

// Route to the correct Google sync operation based on flags from DB_ManageItem
const item = $json;
const result = { ...item, _google_sync_result: '' };

// Pass through - the IF nodes after this will route to the correct HTTP Request
return [{ json: result }];

// Merge Google sync results back into the item data
const item = $('DB_ManageItem').item.json;
let syncResult = '';

// Check if Google Calendar delete succeeded
if (item._needs_google_calendar_delete) {
  try {
    const gcalResult = $('GCal_DeleteEvent').item.json;
    if (gcalResult.error) {
      syncResult += '\n⚠️ Não foi possível remover do Google Calendar: ' + (gcalResult.error.message || 'erro desconhecido');
    } else {
      syncResult += '\n✅ Removido do Google Calendar';
    }
  } catch(e) {
    syncResult += '\n✅ Removido do Google Calendar';
  }
}

if (item._needs_google_calendar_update) {
  try {
    const gcalResult = $('GCal_UpdateEvent').item.json;
    if (gcalResult.error) {
      syncResult += '\n⚠️ Não foi possível atualizar no Google Calendar: ' + (gcalResult.error.message || 'erro desconhecido');
    } else {
      syncResult += '\n✅ Atualizado no Google Calendar';
    }
  } catch(e) {
    syncResult += '\n✅ Atualizado no Google Calendar';
  }
}

if (item._needs_google_tasks_done) {
  try {
    const gtResult = $('GTasks_CompleteTask').item.json;
    if (gtResult.error) {
      syncResult += '\n⚠️ Não foi possível concluir no Google Tasks: ' + (gtResult.error.message || 'erro desconhecido');
    } else {
      syncResult += '\n✅ Concluída no Google Tasks';
    }
  } catch(e) {
    syncResult += '\n✅ Concluída no Google Tasks';
  }
}

return [{ json: { ...item, _google_sync_result: syncResult } }];
